#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long X,Y,P,Q; scanf("%lld %lld %lld %lld",&X,&Y,&P,&Q);
        long long chef = X + 10*P;
        long long chefina = Y + 10*Q;
        if(chef < chefina) printf("Chef\n");
        else if(chef > chefina) printf("Chefina\n");
        else printf("Draw\n");
    }
    return 0;
}

