import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); P = int(next(it)); Q = int(next(it))
        chef = X + 10 * P
        chefina = Y + 10 * Q
        if chef < chefina:
            out.append('Chef')
        elif chef > chefina:
            out.append('Chefina')
        else:
            out.append('Draw')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

